import numpy as np

def equal_width_binning(x: np.ndarray, n_bins: int) -> np.ndarray:
    x_min, x_max = x.min(), x.max()
    if x_min == x_max:
        return np.zeros(len(x), dtype=int)
    edges = np.linspace(x_min, x_max, n_bins + 1)
    bins = np.searchsorted(edges[1:-1], x, side='right')
    return bins.astype(int)

def equal_freq_binning(x: np.ndarray, n_bins: int) -> np.ndarray:
    quantiles = np.linspace(0, 100, n_bins + 1)
    edges = np.percentile(x, quantiles)
    # Remove duplicate edges
    edges = np.unique(edges)
    bins = np.searchsorted(edges[1:-1], x, side='right')
    return np.clip(bins, 0, n_bins - 1).astype(int)
